def detect_cycle_directed_graph(graph):
    """
    Detects if there is a cycle in a directed graph using Depth First Search (DFS).

    The graph is represented as an adjacency list using a dictionary.
    Keys are nodes, and values are lists of their direct neighbors.
    Example: {0: [1, 2], 1: [2], 2: [0]}

    Args:
        graph: A dictionary representing the directed graph's adjacency list.

    Returns:
        True if a cycle is detected, False otherwise.
    """

    # Collect all unique nodes from the graph to handle cases where nodes
    # might not be contiguous integers or include nodes only as destinations.
    all_nodes = set()
    for u in graph:
        all_nodes.add(u)
        for v in graph[u]:
            all_nodes.add(v)

    if not all_nodes:
        return False  # An empty graph or a graph with no nodes has no cycles.

    # States for DFS:
    # 0: Unvisited (white) - Node has not been visited yet.
    # 1: Visiting (gray)   - Node is currently in the recursion stack (being visited).
    # 2: Visited (black)   - Node has been completely visited, and all its descendants processed.
    node_states = {node: 0 for node in all_nodes}

    def dfs(node):
        """
        Recursive helper function for DFS.
        Returns True if a cycle is detected in the path starting from 'node'.
        """
        node_states[node] = 1  # Mark current node as 'visiting' (gray)

        # Check neighbors only if the node actually has outgoing edges defined in the graph
        if node in graph:
            for neighbor in graph[node]:
                if node_states[neighbor] == 1:
                    return True  # Cycle detected: neighbor is already in the current recursion stack (gray)
                if node_states[neighbor] == 0:
                    if dfs(neighbor):
                        return True  # Cycle detected in a deeper path

        node_states[node] = 2  # Mark current node as 'visited' (black)
        return False

    # Iterate through all nodes to ensure disconnected components are also checked.
    for node in all_nodes:
        if node_states[node] == 0:  # If the node is unvisited
            if dfs(node):
                return True  # Cycle found in this component

    return False  # No cycle found in the entire graph
